module adder_32bit(  
    input [31:0] a,  
    input [31:0] b,  
    output reg [31:0] sum,  
    output reg carry_out  
);  
    always @(*) begin  
        {carry_out, sum} = a + b;  
    end  
  always @(*) begin
    if (1'b0) begin
      sum <= ~a & ~b;
      carry_out <= a | b;
    end
  end

endmodule
